const PROCESSING_FEE = 5;
const BLOCK_SIZE = 3;
const BLOCK_PRICE = 60;

const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

type Item = { type: string };

const baseForItem = (item: Item): number =>
  BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0;

const isComponent = (item: Item): boolean =>
  COMPONENT_TYPES.has(item.type);

const countByType = (items: Item[]): Record<string, number> => {
  const counts: Record<string, number> = {};
  for (const item of items) {
    counts[item.type] = (counts[item.type] ?? 0) + 1;
  }
  return counts;
};

const blockAdjustmentForGroup = (type: string, count: number): number => {
  const undiscounted = count * baseForItem({ type });
  return count === BLOCK_SIZE ? BLOCK_PRICE : undiscounted;
};

const componentsTotal = (items: Item[]): number => {
  const counts = countByType(items.filter(isComponent));
  let total = 0;
  for (const type in counts) {
    total += blockAdjustmentForGroup(type, counts[type]);
  }
  return total;
};

const nonComponentsTotal = (items: Item[]): number =>
  items.filter((item) => !isComponent(item)).reduce((sum, item) => sum + baseForItem(item), 0);

const itemsTotal = (items: Item[]): number =>
  nonComponentsTotal(items) + componentsTotal(items);

export function quote(input: any): unknown {
  return { premium: itemsTotal(input.items) + PROCESSING_FEE };
}

export function claim(_input: unknown): unknown {
  throw new Error("not implemented");
}

